Q1:Binary search on answer
```
#include<bits/stdc++.h>
using namespace std;
const int INF=1e9+7;

bool pos(int val,vector<int>& nums,int n){  //greedy checker function
    int len=nums.size();
    int curr=0;
    for(int i=0;i<len;i++){
        curr+=val/nums[i] ;
        if(curr>=n)
            return true;
    }
    return false;
}

int solve(vector<int> &nums,int n){
    int l=0,r=INF;
    int ans=INF;
    while(l<r){
        int mid=l+(r-l)/2;
        if(pos(mid ,nums, n)){
            ans=min(ans,mid);
            r=mid;
        }
        else
            l=mid+1;
    }
    return ans;

}
int main(){
    vector<int> vec={1,3,5,7,8};
    int n=10;
    cout<<solve(vec,n);   
}
```
Q2: merge intervals
```
#include<bits/stdc++.h>
using namespace std;

int solve(vector<vector<int>> &loc){
    int n=loc.size();
    sort(loc.begin(),loc.end());  //sorts with starting co-ordinates of cab.
    int ans=0;
    for(int i=0;i<n;i++){
        int start=loc[i][0],end=loc[i][1];
        while(i<n && loc[i][0]<= end){
            end=max(end,loc[i][1]);
            i++;
        }
        i--;
        ans+=(end-start+1);
    }
    return ans;
}
int main(){
    vector<vector<int>> loc={{4,7},{-1,5},{3,6}};
    cout<<solve(loc);   
}
