using namespace std;

int easyCountUber(const vector<pair<int, int>>& coordinates) {
    map<int, int> events;

    // Mark the start and end of coverage for each uber
    for (const auto& range : coordinates) {
        int st = range.first;
        int end = range.second;

        // Increment at the start of the range
        events[st]++;

        // Decrement just after the end of the range (exclusive)
        events[end + 1]--;
    }

    int count = 0;
    int activeCoverage = 0;
    int totalcoveredmarkeres = 0;

    // Iterate over all events sorted by marker position
    for (const auto& event : events) {
        // Calculate the number of covered markers since the last event
        if (activeCoverage > 0) {
            count += event.first - totalcoveredmarkeres;
        }

        // Update active coverage
        activeCoverage += event.second;

        // Update totalcoveredmarkeres
         totalcoveredmarkeres = event.first;
    }

    return count;
}

int main() {
    vector<pair<int, int>> coordinates = {{4, 7}, {-1, 5}, {3, 6}};
    cout << "Number of markers covered by at least one uber: " 
         << easyCountUber(coordinates) << endl;
    return 0;
}

