using namespace std;

bool canComplete(int time, int n, const vector<int>& cabTravelTime) {
    int tripsPossible = 0;
    for (std::vector<int>::size_type i = 0; i < cabTravelTime.size(); i++) {
        tripsPossible += time / cabTravelTime[i];
    }
    return tripsPossible >= n;
}

int minTimeToCompleteTrips(int n, const vector<int>& cabTravelTime) {
    int st = 0, end = *max_element(cabTravelTime.begin(), cabTravelTime.end()) * n;
    int result = end;

    while (st <= end) {
        int mid = st + (end - st) / 2;

        if (canComplete(mid, n, cabTravelTime)) {
            result = mid;
            end = mid - 1;
        } else {
            st = mid + 1;
        }
    }
    return result;
}

int main() {
    int n = 10;
    vector<int> cabTravelTime = {2, 5, 6, 7, 9, 12};

    cout << "Minimum time to complete " << n << " trips: " 
         << minTimeToCompleteTrips(n, cabTravelTime) << endl;

    return 0;
}

Java Solution for Question 2:

Time Complexity: O(NlogN)
Space Complexity: O(1)

```
import java.util.Arrays;
import java.util.Comparator;

public class Solution {
    public static void main(String[] args) {
        System.out.println(easyCountUber(new int[][]{{4, 7}, {-1, 5}, {3, 6}}));
        System.out.println(easyCountUber(new int[][]{{1, 3}, {2, 6}, {8, 10}, {15, 18}}));
    }

    public static int easyCountUber(int[][] coordinates) {
        if(coordinates.length == 0) {
            return 0;
        }

        Arrays.sort(coordinates, Comparator.comparingInt(a -> a[0]));

        int mergedStart = coordinates[0][0];
        int mergedEnd = coordinates[0][1];
        int markers = 0;

        for(int i = 1; i < coordinates.length; i++) {
            if(coordinates[i][0] <= mergedEnd) {
                mergedEnd = Math.max(mergedEnd, coordinates[i][1]);
            } else {
                markers += mergedEnd - mergedStart + 1;
                mergedStart = coordinates[i][0];
                mergedEnd = coordinates[i][1];
            }
        }

        markers += mergedEnd - mergedStart + 1;
        return markers;
    }
}
