import java.util.Arrays;

public class Solution {
    public static void main(String[] args) {
        System.out.println(minimumTimeRequired(2, new int[]{1, 2}));
        System.out.println(minimumTimeRequired(10, new int[]{1, 3, 5, 7, 8}));
        System.out.println(minimumTimeRequired(3, new int[]{3, 4, 8}));
    }

    public static int minimumTimeRequired(int numTrips, int[] cabTravelTime) {
        int left = 1;
        int right = numTrips * Arrays.stream(cabTravelTime).min().orElse(Integer.MAX_VALUE);

        while(left < right) {
            int mid = left + (right - left) / 2;
            if (canCompleteTrip(numTrips, cabTravelTime, mid)) {
                right = mid;
            } else {
                left = mid + 1;
            }
        }
        return left;
    }

    private static boolean canCompleteTrip(int numTrips, int[] cabTravelTime, int time) {
        int trips = 0;
        for (int travelTime : cabTravelTime) {
            trips += time / travelTime;
            if (trips >= numTrips) {
                return true;
            }
        }
        return trips >= numTrips;
    }
}
